let msg1 = {}; //switch 
let msg2 = {}; //target temperature
let msg3 = {}; //Set setHysteresisPlus
let msg4 = {}; //Set setHysteresisMinus
let now = new Date(msg.time); // legge l'ora dal msg.time
global.set("time", now);
let setPointAuto

let riscaldamentoModo = global.get("riscaldamentoModo");
//let condizionamentoModo = global.get("condizionamentoModo");
let setPointManuale = global.get("setPointManuale");
let tempCurrent = global.get("tempCurrent");

// Rimuovi tutto ciò che non è un numero o un separatore decimale
let tempNumber = parseFloat(tempCurrent.replace(',', '.').replace(/[^0-9.-]/g, ''));

//let timing = global.get("timing");
let timing = context.global.timing

//Lettura setpoint in base alla data/ora
setPointAuto = timing[(now.getDay() * 24) + now.getHours() ];
global.set("setPointAuto", setPointAuto);

// Payload per il termostato riscaldamento
if (riscaldamentoModo == 1) {   //auto
    msg1.topic = "setCurrent" // Topic per valore di temperatura attuale
    msg1.payload = tempNumber // Valore di temperatura rilevato dal sensore
    msg2.topic = "setTarget" // Topic per valore di temperatura programmato
    msg2.payload = setPointAuto // Valore di temperatura previsto dalla programmazione
    msg3.topic = "setHysteresisPlus"
    msg3.payload = 0.1
    msg4.topic = "setHysteresisMinus"
    msg4.payload = 0.2
    return [msg1, msg2, msg3, msg4];
}
else if (riscaldamentoModo == 2) { //Disattivo
    msg1.topic = "setCurrent"
    msg1.payload = tempNumber // Valore di temperatura rilevato dal sensore
    msg2.topic = "setTarget" // Topic per valore di temperatura programmato
    msg2.payload = tempNumber // Valore di temperatura setpoint uguale alla temperatura corrente
    msg3.topic = "setHysteresisPlus"
    msg3.payload = 0
    msg4.topic = "setHysteresisMinus"
    msg4.payload = 0
    return [msg1, msg2, msg3, msg4];
}
else if (riscaldamentoModo == 3) { //Manuale
    msg1.topic = "setCurrent"
    msg1.payload = tempNumber // Valore di temperatura rilevato dal sensore
    msg2.topic = "setTarget" // Topic per valore di temperatura programmato
    msg2.payload = setPointManuale // Valore di temperatura previsto dalla programmazione
    msg3.topic = "setHysteresisPlus"
    msg3.payload = 0.1
    msg4.topic = "setHysteresisMinus"
