// Nodo Funzione Node-RED

// Variabili globali da utilizzare
let riscaldamentoModo = global.get('riscaldamentoModo') || 2; // Modalità riscaldamento automatico (1) o manuale (3) o disabilitato (2)
let riscaldamentoHvAC = global.get('riscaldamentoHvAC') || 0; // Modalità riscaldamento HVAC 0=GAS ONLY, 1=GAS+ENE
let setPointAuto = global.get('setPointAuto') || 20; // Setpoint automatico
let setPointManuale = global.get('setPointManuale') || 22; // Setpoint manuale
let ore = global.get("setOre") //ora di Roma con cambio ora legale automatico
let hvacMode = global.get('hvacMode') || 1; // Modo di funzionamento del condizionamento 1 Inverno, 2 Estate

// Stato attuale dei dispositivi
let statoCond1 = global.get('statoCond1') || "OFF";
let statoCond2 = global.get('statoCond2') || "OFF";
let statoCond3 = global.get('statoCond3') || "OFF";
let statoCond4 = global.get('statoCond4') || "OFF";
let statoCaldaia = global.get('statoCaldaia') || "OFF";

// Input dal messaggio
const consenso = msg.payload === true; // Consenso del cronotermostato

// Calcolo degli stati degli output
let outputCond1 = null;
let outputCond2 = null;
let outputCond3 = null;
let outputCond4 = null;
let outputCaldaia = null;
let outputSetPoint = null;

// Logica per i condizionatori (out1, out2, out3, out4)
if (riscaldamentoHvAC == 1 && riscaldamentoModo != 2 && consenso && setPointAuto != 18) {
    if (statoCond1 !== "ON") {
        outputCond1 = { payload: "ON" };
    }
    if (statoCond2 !== "ON") {
        outputCond2 = { payload: "ON" };
    }
    if (statoCond3 !== "ON") {
        outputCond3 = { payload: "ON" };
    }
    if (statoCond4 !== "ON") {
        outputCond4 = { payload: "ON" };
    }
}
else if (ore > 23 && hvacMode == 1 ) { //se dopo 23 e se la modalità dei condizionatori è inverno
    if (statoCond1 !== "OFF") {
        outputCond1 = { payload: "OFF" };
    }
    if (statoCond2 !== "OFF") {
        outputCond2 = { payload: "OFF" };
    }
    if (statoCond3 !== "OFF") {
        outputCond3 = { payload: "OFF" };
    }
    if (statoCond4 !== "OFF") {
        outputCond4 = { payload: "OFF" };
    }
}

// Logica per la caldaia (out5)
if (riscaldamentoModo != 2 && consenso) {
    if (statoCaldaia !== "ON") {
        outputCaldaia = { payload: "ON" };
    }
} else {
    if (statoCaldaia !== "OFF") {
        outputCaldaia = { payload: "OFF" };
    }
}

// Logica per il setpoint (out6)
if (consenso) {
    if (riscaldamentoModo == 1) {
        outputSetPoint = { payload: setPointAuto };
    } else if (riscaldamentoModo == 3) {
        outputSetPoint = { payload: setPointManuale };
    } else {
        outputSetPoint = { payload: null };
    }
}

node.status({ fill: "red", shape: "dot", text: "consenso " + consenso + " riscaldamentoHvAC: " + riscaldamentoHvAC + " riscaldamentoModo " + riscaldamentoModo});

// Invio degli output
return [outputCond1, outputCond2, outputCond3, outputCond4, outputCaldaia, outputSetPoint];
